import { useState, useEffect } from 'react'
import { NavLink, useLocation } from 'react-router-dom'
import './Navbar.css'

/* ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
   3D Padlock Logo
   Techniques:
   ÔÇó Layered shackle paths (shadow ÔåÆ main gold ÔåÆ specular)
     simulates a cylindrical metal tube
   ÔÇó Body with gradient fill + top highlight band + bottom shadow
   ÔÇó Drop shadow rect offset behind body for depth
   ÔÇó Metallic gradient on body border
   ÔÇó Icons inside unchanged
ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ*/
function PadlockIcon({ size = 18 }) {
    return (
        <img
            src="/logo.png"
            alt="Anonastr Logo"
            style={{ width: size, height: size, objectFit: 'contain' }}
            className="logo-img"
        />
    )
}
import { EyeIcon, KeyIcon, ChartIcon, TagIcon, SweeperIcon, ShieldIcon, BundlerIcon, SniperIcon } from './icons'

function GithubIcon({ size = 18 }) {
    return (
        <svg width={size} height={size} viewBox="0 0 24 24" fill="currentColor">
            <path d="M12 2C6.477 2 2 6.477 2 12c0 4.42 2.865 8.166 6.839 9.489.5.092.682-.217.682-.482 0-.237-.008-.866-.013-1.7-2.782.603-3.369-1.34-3.369-1.34-.454-1.156-1.11-1.462-1.11-1.462-.908-.62.069-.608.069-.608 1.003.07 1.531 1.03 1.531 1.03.892 1.529 2.341 1.087 2.91.831.092-.646.35-1.086.636-1.336-2.22-.253-4.555-1.11-4.555-4.943 0-1.091.39-1.984 1.029-2.683-.103-.253-.446-1.27.098-2.647 0 0 .84-.269 2.75 1.025A9.564 9.564 0 0112 6.844c.85.004 1.705.114 2.504.336 1.909-1.294 2.747-1.025 2.747-1.025.546 1.379.203 2.394.1 2.647.64.699 1.028 1.592 1.028 2.683 0 3.842-2.339 4.687-4.566 4.935.359.309.678.919.678 1.852 0 1.336-.012 2.415-.012 2.743 0 .267.18.578.688.48C19.138 20.161 22 16.418 22 12c0-5.523-4.477-10-10-10z" />
        </svg>
    )
}

function TwitterIcon({ size = 18 }) {
    return (
        <svg width={size} height={size} viewBox="0 0 24 24" fill="currentColor">
            <path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-5.214-6.817L4.99 21.75H1.68l7.73-8.835L1.254 2.25H8.08l4.713 6.231zm-1.161 17.52h1.833L7.084 4.126H5.117z" />
        </svg>
    )
}

const navItems = [
    { path: '/exposure', label: 'Exposure', Icon: EyeIcon },
    { path: '/stealth', label: 'Stealth Wallet', Icon: KeyIcon },
    { path: '/sweeper', label: 'Dust Sweeper', Icon: SweeperIcon },
    { path: '/revoke', label: 'Approval Revoker', Icon: ShieldIcon },
    { path: '/bundle', label: 'Wallet Bundler', Icon: BundlerIcon },
    { path: '/sniper', label: 'Mempool Sniper', Icon: SniperIcon },
    { path: '/pnl', label: 'PnL Card', Icon: ChartIcon },
    { path: '/tag', label: 'Anon Tag', Icon: TagIcon },
]

export default function Navbar() {
    const [scrolled, setScrolled] = useState(false)
    const [menuOpen, setMenuOpen] = useState(false)
    const location = useLocation()

    useEffect(() => {
        const onScroll = () => setScrolled(window.scrollY > 20)
        window.addEventListener('scroll', onScroll)
        return () => window.removeEventListener('scroll', onScroll)
    }, [])

     
    useEffect(() => setMenuOpen(false), [location])

    return (
        <nav className={`navbar ${scrolled ? 'scrolled' : ''}`}>
            <div className="navbar-inner">
                <NavLink to="/" className="navbar-logo">
                    <PadlockIcon size={52} />
                    <span className="logo-text">Anonastr</span>
                </NavLink>

                <div className={`navbar-links ${menuOpen ? 'open' : ''}`}>
                    {navItems.map((item) => {
                        const IconComponent = item.Icon
                        return (
                            <NavLink key={item.path} to={item.path}
                                className={({ isActive }) => `nav-link ${isActive ? 'active' : ''}`}>
                                <IconComponent />
                                {item.label}
                            </NavLink>
                        )
                    })}
                </div>

                <div className="navbar-right" style={{ display: 'flex', gap: '8px' }}>
                    <a href="https://github.com/anonastr/anonastr" target="_blank" rel="noopener noreferrer" style={{ color: 'var(--text-secondary)', display: 'flex', alignItems: 'center', transition: 'color 0.2s', padding: '8px' }} onMouseOver={e => e.currentTarget.style.color = '#fff'} onMouseOut={e => e.currentTarget.style.color = 'var(--text-secondary)'}>
                        <GithubIcon size={20} />
                    </a>
                    <a href="https://x.com/anonastr" target="_blank" rel="noopener noreferrer" style={{ color: 'var(--text-secondary)', display: 'flex', alignItems: 'center', transition: 'color 0.2s', padding: '8px' }} onMouseOver={e => e.currentTarget.style.color = '#fff'} onMouseOut={e => e.currentTarget.style.color = 'var(--text-secondary)'}>
                        <TwitterIcon size={20} />
                    </a>
                    <button className="hamburger" onClick={() => setMenuOpen(o => !o)} aria-label="menu">
                        <span /><span /><span />
                    </button>
                </div>
            </div>
        </nav>
    )
}

import { useState } from 'react'
import { ethers } from 'ethers'
import { SweeperIcon } from '../components/icons'
import './DustSweeper.css'

const RPC_URL = 'https://data-seed-prebsc-1-s1.binance.org:8545'

export default function DustSweeper() {
    const [privateKeys, setPrivateKeys] = useState('')
    const [destination, setDestination] = useState('')
    const [loading, setLoading] = useState(false)
    const [results, setResults] = useState([])
    const [error, setError] = useState('')

    async function sweepDust() {
        setError('')
        setResults([])

        const dest = destination.trim()
        if (!ethers.isAddress(dest)) {
            setError('Invalid destination address.')
            return
        }

        const keys = privateKeys.split('\n').map(k => k.trim()).filter(Boolean)
        if (keys.length === 0) {
            setError('Please enter at least one private key.')
            return
        }

        setLoading(true)
        const newResults = []
        const provider = new ethers.JsonRpcProvider(RPC_URL)

        try {
            for (const pk of keys) {
                let wallet
                try {
                    wallet = new ethers.Wallet(pk, provider)
                } catch {
                    newResults.push({ key: pk.slice(0, 10) + '...', status: 'error', message: 'Invalid private key' })
                    continue
                }

                try {
                    const balance = await provider.getBalance(wallet.address)
                    if (balance === 0n) {
                        newResults.push({ address: wallet.address, status: 'skipped', message: '0 balance' })
                        continue
                    }

                    // Estimate gas for a simple transfer
                    const gasLimit = 21000n // Standard ETH transfer
                    const feeData = await provider.getFeeData()
                    const gasPrice = feeData.gasPrice || (await provider.getBlock('latest')).baseFeePerGas

                    const gasCost = gasLimit * gasPrice

                    if (balance <= gasCost) {
                        newResults.push({
                            address: wallet.address,
                            status: 'skipped',
                            message: `Balance too low to cover gas (${ethers.formatEther(balance)} ETH)`
                        })
                        continue
                    }

                    // Subtract gas cost from balance to send the maximum possible
                    const amountToSend = balance - gasCost

                    const tx = await wallet.sendTransaction({
                        to: dest,
                        value: amountToSend,
                        gasLimit: gasLimit,
                        gasPrice: gasPrice
                    })

                    newResults.push({
                        address: wallet.address,
                        status: 'success',
                        message: `Sent ${ethers.formatEther(amountToSend)} ETH`,
                        hash: tx.hash
                    })
                } catch (err) {
                    newResults.push({ address: wallet.address, status: 'error', message: err.message || 'Transaction failed' })
                }
            }
            setResults(newResults)
        } catch (e) {
            setError('An unexpected error occurred during sweeping.')
        } finally {
            setLoading(false)
        }
    }

    return (
        <div className="page fade-up">
            <h1 className="page-title">Dust Sweeper</h1>
            <p className="page-subtitle">Got 10 burner wallets with $1 of ETH left in each? Sweep them all to a single cold wallet in one click.</p>

            <div className="alert alert-warning" style={{ marginBottom: 24, alignItems: 'flex-start' }}>
                <SweeperIcon style={{ width: 22, height: 22, flexShrink: 0, marginTop: 2, stroke: '#fcd34d' }} />
                <div>
                    <strong>Secure & Local:</strong> Your private keys never leave your browser. Transactions are signed locally and broadcasted directly to the RPC.
                </div>
            </div>

            <div className="card">
                <div className="input-group">
                    <label className="input-label">Destination Address</label>
                    <input
                        className="input"
                        placeholder="0x... (Where to send the funds)"
                        value={destination}
                        onChange={e => setDestination(e.target.value)}
                        spellCheck={false}
                    />
                </div>

                <div className="input-group">
                    <label className="input-label">Burner Private Keys (One per line)</label>
                    <textarea
                        className="input"
                        placeholder="0xabc123...&#10;0xdef456...&#10;..."
                        value={privateKeys}
                        onChange={e => setPrivateKeys(e.target.value)}
                        spellCheck={false}
                        style={{ minHeight: 120, resize: 'vertical' }}
                    />
                </div>

                {error && <div className="alert alert-warning" style={{ marginBottom: 16 }}>ÔÜá´©Å {error}</div>}

                <button
                    className="btn btn-primary"
                    onClick={sweepDust}
                    disabled={loading || !destination || !privateKeys}
                    style={{ width: '100%' }}
                >
                    {loading ? <><span className="loader" /> Sweeping Dust...</> : <><SweeperIcon color="black" style={{ width: 18, height: 18 }} /> Sweep All Dust</>}
                </button>
            </div>

            {results.length > 0 && (
                <div className="card fade-up" style={{ marginTop: 24 }}>
                    <h3 style={{ marginBottom: 16, fontFamily: 'var(--font-display)', fontSize: '1rem' }}>­ƒº╣ Sweep Results</h3>
                    <div className="results-list" style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                        {results.map((r, i) => (
                            <div key={i} className={`result-item ${r.status}`} style={{
                                padding: '12px',
                                borderRadius: '8px',
                                display: 'flex',
                                justifyContent: 'space-between',
                                alignItems: 'center',
                                background: r.status === 'success' ? 'rgba(16, 185, 129, 0.1)' :
                                    r.status === 'error' ? 'rgba(239, 68, 68, 0.1)' : 'rgba(255, 255, 255, 0.05)',
                                border: `1px solid ${r.status === 'success' ? 'rgba(16, 185, 129, 0.2)' :
                                    r.status === 'error' ? 'rgba(239, 68, 68, 0.2)' : 'rgba(255, 255, 255, 0.1)'}`
                            }}>
                                <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                                    <span style={{ fontFamily: 'var(--font-mono)', fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                                        {r.address ? `${r.address.slice(0, 6)}...${r.address.slice(-4)}` : r.key}
                                    </span>
                                    <span style={{
                                        fontSize: '0.9rem',
                                        color: r.status === 'success' ? '#10b981' : r.status === 'error' ? '#ef4444' : 'var(--text-secondary)'
                                    }}>
                                        {r.message}
                                    </span>
                                </div>
                                {r.hash && (
                                    <a
                                        href={`https://testnet.bscscan.com/tx/${r.hash}`}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        style={{ fontSize: '0.85rem', color: 'var(--brand)', textDecoration: 'none' }}
                                    >
                                        View Tx Ôåù
                                    </a>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    )
}
